"use client";

import { useSearchParams } from "next/navigation";
import { Fragment } from "react";

// Ensure children are re-rendered when the search query changes
export default function ChildrenWrapper({
  children,
}: {
  children: React.ReactNode;
}) {
  const searchParams = useSearchParams();
  return <Fragment key={searchParams.get("q")}>{children}</Fragment>;
}

React.useEffect(() => {
    if (requiredAndNotLoading) {
      const url = `${__NEXTAUTH.basePath}/signin?${new URLSearchParams({
        error: "SessionRequired",
        callbackUrl: window.location.href,
      })}`
      if (onUnauthenticated) onUnauthenticated()
      else window.location.href = url
    }
  }, [requiredAndNotLoading, onUnauthenticated])

React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${mobileBreakpoint - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < mobileBreakpoint)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < mobileBreakpoint)
    return () => mql.removeEventListener("change", onChange)
  }, [mobileBreakpoint])

return (
  <HoverCardPrimitive.Portal data-slot="hover-card-portal">
    <HoverCardPrimitive.Content
      data-slot="hover-card-content"
      align={align}
      sideOffset={sideOffset}
      className={cn(
        "cn-hover-card-content z-50 origin-(--radix-hover-card-content-transform-origin) outline-hidden",
        className
      )}
      {...props}
    />
  </HoverCardPrimitive.Portal>
)

return (
  <MenubarPortal>
    <MenubarPrimitive.Content
      data-slot="menubar-content"
      align={align}
      alignOffset={alignOffset}
      sideOffset={sideOffset}
      className={cn(
        "cn-menubar-content cn-menu-target cn-menu-translucent z-50 origin-(--radix-menubar-content-transform-origin) overflow-hidden",
        className
      )}
      {...props}
    />
  </MenubarPortal>
)

return (
  <NavigationMenuPrimitive.Root
    data-slot="navigation-menu"
    data-viewport={viewport}
    className={cn(
      "cn-navigation-menu group/navigation-menu relative flex max-w-max flex-1 items-center justify-center",
      className
    )}
    {...props}
  >
    {children}
    {viewport && <NavigationMenuViewport />}
  </NavigationMenuPrimitive.Root>
)

return (
  <ProgressPrimitive.Root
    data-slot="progress"
    className={cn(
      "cn-progress relative flex w-full items-center overflow-x-hidden",
      className
    )}
    {...props}
  >
    <ProgressPrimitive.Indicator
      data-slot="progress-indicator"
      className="cn-progress-indicator size-full flex-1 transition-all"
      style={{ transform: `translateX(-${100 - (value || 0)}%)` }}
    />
  </ProgressPrimitive.Root>
)

return {
  handlers: { GET: httpHandler, POST: httpHandler } as const,
  // @ts-expect-error
  auth: initAuth(config),
  signIn: (provider, options, authorizationParams) => {
    return signIn(provider, options, authorizationParams, config)
  },
  signOut: (options) => {
    return signOut(options, config)
  },
  unstable_update: (data) => {
    return update(data, config)
  },
}

const inputGroupButtonVariants = cva(
  "cn-input-group-button flex items-center shadow-none",
  {
    variants: {
      size: {
        xs: "cn-input-group-button-size-xs",
        sm: "cn-input-group-button-size-sm",
        "icon-xs": "cn-input-group-button-size-icon-xs",
        "icon-sm": "cn-input-group-button-size-icon-sm",
      },
    },
    defaultVariants: {
      size: "xs",
    },
  }
)

const verificationTokensTable =
    schema.verificationTokensTable ??
    (pgTable(
      "verificationToken",
      {
        identifier: text("identifier").notNull(),
        token: text("token").notNull(),
        expires: timestamp("expires", { mode: "date" }).notNull(),
      },
      (verificationToken) => ({
        compositePk: primaryKey({
          columns: [verificationToken.identifier, verificationToken.token],
        }),
      })
    ) satisfies DefaultPostgresVerificationTokenTable)

const componentsJson = {
  $schema: "https://ui.shadcn.com/schema.json",
  style: `${config.base}-${config.style}`,
  tailwind: {
    css: "app/globals.css",
    baseColor: config.baseColor,
  },
  iconLibrary: config.iconLibrary,
  aliases: {
    components: "@/components",
    utils: "@/lib/utils",
    ui: "@/components/ui",
    lib: "@/lib",
    hooks: "@/hooks",
  },
}

for (const declaration of sourceFile.getImportDeclarations()) {
  if (declaration.getModuleSpecifierValue() !== "next/font/google") {
    continue
  }

  for (const namedImport of declaration.getNamedImports()) {
    const importedName = namedImport.getName()
    const localName = namedImport.getAliasNode()?.getText() ?? importedName
    const font = parseFontFromNextImport(importedName)
    if (font) {
      importedFonts.set(localName, font)
    }
  }
}

const sync = async () => {
  if (process.env.NODE_ENV !== "production" && synchronize && !_synced) {
    const syncOptions =
      typeof synchronize === "object" ? synchronize : undefined

    await Promise.all([
      User.sync(syncOptions),
      Account.sync(syncOptions),
      Session.sync(syncOptions),
      VerificationToken.sync(syncOptions),
    ])

    _synced = true
  }
}

const c = {
  dataSource,
  entities: {
    UserEntity: entities?.UserEntity ?? defaultEntities.UserEntity,
    SessionEntity: entities?.SessionEntity ?? defaultEntities.SessionEntity,
    AccountEntity: entities?.AccountEntity ?? defaultEntities.AccountEntity,
    VerificationTokenEntity:
      entities?.VerificationTokenEntity ??
      defaultEntities.VerificationTokenEntity,
  },
}

if (
  hasEmail ||
  session?.strategy === "database" ||
  (!session?.strategy && adapter)
) {
  if (hasEmail) {
    if (!adapter) return new MissingAdapter("Email login requires an adapter")
    requiredMethods.push(...emailMethods)
  } else {
    if (!adapter)
      return new MissingAdapter("Database session requires an adapter")
    requiredMethods.push(...sessionMethods)
  }
}

if (cookieValue) {
  const [csrfToken, csrfTokenHash] = cookieValue.split("|")

  const expectedCsrfTokenHash = await createHash(
    `${csrfToken}${options.secret}`
  )

  if (csrfTokenHash === expectedCsrfTokenHash) {
    // If hash matches then we trust the CSRF token value
    // If this is a POST request and the CSRF Token in the POST request matches
    // the cookie we have already verified is the one we have set, then the token is verified!
    const csrfTokenVerified = isPost && csrfToken === bodyValue

    return { csrfTokenVerified, csrfToken }
  }
}

const metrics = getClientComponentLoaderMetrics()
          if (metrics) {
            performance.measure(
              `${process.env.NEXT_OTEL_PERFORMANCE_PREFIX}:next-client-component-loading`,
              {
                start: metrics.clientComponentLoadStart,
                end:
                  metrics.clientComponentLoadStart +
                  metrics.clientComponentLoadTimes,
              }
            )
          }

const params = Object.assign(
  {
    response_type: "code",
    // clientId can technically be undefined, should we check this in assert.ts or rely on the Authorization Server to do it?
    client_id: provider.clientId,
    redirect_uri,
    // @ts-expect-error TODO:
    ...provider.authorization?.params,
  },
  Object.fromEntries(provider.authorization?.url.searchParams ?? []),
  query
)

if (config.menuAccent === "bold") {
  lightVars.accent = lightVars.primary
  lightVars["accent-foreground"] = lightVars["primary-foreground"]
  darkVars.accent = darkVars.primary
  darkVars["accent-foreground"] = darkVars["primary-foreground"]
  // lightVars["sidebar-accent"] = lightVars.primary
  // lightVars["sidebar-accent-foreground"] = lightVars["primary-foreground"]
  // darkVars["sidebar-accent"] = darkVars.primary
  // darkVars["sidebar-accent-foreground"] = darkVars["primary-foreground"]
}

if (
  process.env.NODE_ENV !== 'production' &&
  typeof getConfig !== 'function'
) {
  throw new Error(
    `Invalid i18n request configuration detected.

Please verify that:
1. In case you've specified a custom location in your Next.js config, make sure that the path is correct.
2. You have a default export in your i18n request configuration file.

See also: https://next-intl.dev/docs/usage/configuration#i18n-request
`
  );
}

return createTranslatorImpl<
    {'!': TranslatorMessages},
    [Namespace] extends [never] ? '!' : `!.${Namespace}`
  >(
    {
      ...rest,
      onError,
      cache: _cache,
      formatters: _formatters,
      getMessageFallback,
      // @ts-expect-error `messages` is allowed to be `undefined` here and will be handled internally
      messages: {'!': messages},
      namespace: namespace ? `!.${namespace}` : '!'
    },
    '!'
  );
